1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: string; items: Item[] };
12	type Scenario = { steps: Step[] };
13	
14	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
15	  const s = scenario as Scenario;
16	  const step = s.steps[0];
17	  const itemsBase = step.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
18	  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE;
19	  const policyBase = itemsBase + firstInsuranceSurcharge;
20	  const premium = policyBase + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	}
